import java.util.PriorityQueue;
import java.util.Comparator;
import java.util.ArrayList;
import java.util.List;

public class Solution {
    public int[] assignTasks(int[] servers, int[] tasks) {
        int n = servers.length, m = tasks.length;
        int[] ans = new int[m];
        PriorityQueue<int[]> freeServers = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]).thenComparingInt(a -> a[1]));

        for (int i = 0; i < n; i++) {
            freeServers.offer(new int[]{servers[i], i});
        }

        PriorityQueue<int[]> busyServers = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]).thenComparingInt(a -> a[1]));
        int currentTask = 0;

        while (currentTask < m) {
            while (!busyServers.isEmpty() && busyServers.peek()[0] <= currentTask) {
                freeServers.offer(new int[]{servers[busyServers.peek()[1]], busyServers.peek()[1]});
                busyServers.poll();
            }

            while (!freeServers.isEmpty() && currentTask < m) {
                ans[currentTask] = freeServers.peek()[1];
                busyServers.offer(new int[]{currentTask + tasks[currentTask], freeServers.peek()[1]});
                freeServers.poll();
                currentTask++;
            }

            if(freeServers.isEmpty()) {
                currentTask = busyServers.peek()[0];
            }
        }

        return ans;
    }
}
```

    The algorithm works as follows:
1. Create two priority queues, one for free servers and one for busy servers. Both queues use server weight and index as their sorting criteria.
2. Initially, add all servers to the freeServers queue.
3. Loop through the tasks as `currentTask` and do the following:
   - If there are any busy servers that have become free, move them from the `busyServers` queue to the `freeServers` queue.
   - Assign tasks to free servers from the `freeServers` queue and add the assigned servers to the `busyServers` queue.
   - If no free servers are available, wait until a server becomes free and repeat the process.
4. The final answer will be stored in the `ans` variable, which holds the index of the server assigned to each task.
